import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.jsoup.select.Elements;
import org.jsoup.nodes.TextNode;
import org.jsoup.nodes.Comment;

import static org.junit.jupiter.api.Assertions.*;
public class Element_children_0_Test {

    @Test
    @DisplayName("TC01: children() on element with no child nodes returns empty Elements (childNodeSize()==0 branch)")
    public void test_TC01() {
        // GIVEN an element with no children → childNodeSize()==0 triggers the B1→B2→B5 branch
        Element el = new Element("div");
        // WHEN
        Elements children = el.children();
        // THEN
        assertTrue(children.isEmpty(), "Expected no child elements when none were added");
    }

    @Test
    @DisplayName("TC02: children() on element with single Element child builds list via loop once (childNodeSize()>0, shadowChildrenRef==null, one iteration)")
    public void test_TC02() {
        // GIVEN a parent with one Element child → childNodeSize()>0, shadowChildrenRef==null and loop will run once
        Element parent = new Element("div");
        Element span = parent.appendElement("span"); // one element child
        // WHEN
        Elements children = parent.children();
        // THEN
        assertEquals(1, children.size(), "Expected exactly one child element");
        assertSame(span, children.get(0), "Expected the child to be the appended <span>");
    }

    @Test
    @DisplayName("TC03: children() on element with mixed Node children filters only Element instances (childNodeSize()>0, shadowChildrenRef==null, multiple iterations)")
    public void test_TC03() {
        // GIVEN a parent with mixed children: TextNode, Element, Comment → only one Element should be returned
        Element parent = new Element("div");
        parent.appendChild(new TextNode("text"));  // non-Element node
        Element p = parent.appendElement("p");     // one Element
        parent.appendChild(new Comment("cmt"));    // non-Element node
        // WHEN
        Elements children = parent.children();
        // THEN
        assertEquals(1, children.size(), "Expected exactly one child element after filtering non-Element nodes");
        assertSame(p, children.get(0), "Expected the only Element child to be the <p> element");
    }

    @Test
    @DisplayName("TC04: children() uses cached shadowChildrenRef on second call (shadowChildrenRef!=null branch)")
    public void test_TC04() {
        // GIVEN a parent with one Element child and children() called once to prime cache
        Element parent = new Element("div");
        Element a = parent.appendElement("a");
        Elements first = parent.children(); // prime the shadowChildrenRef cache
        assertEquals(1, first.size(), "Sanity: first call should return one child element");
        // WHEN calling children() again → should hit cache branch (shadowChildrenRef != null)
        Elements second = parent.children();
        // THEN
        assertEquals(1, second.size(), "Expected cached children list to still have one child");
        assertSame(a, second.get(0), "Expected the cached child element to be the same <a>");
    }
}
